fn h380_answer_completeness_ok(
    answer_type: H380AnswerType,
    route: H380Route,
    protected: bool,
) -> bool {
    if protected {
        return answer_type == H380AnswerType::ProtectedFailClosed
            && route == H380Route::ProtectedFailClosed;
    }
    matches!(
        (answer_type, route),
        (H380AnswerType::Provenance, H380Route::FollowupProvenance)
            | (H380AnswerType::Explanation, H380Route::FollowupMeaning)
            | (H380AnswerType::Rephrase, H380Route::FollowupMeaning)
            | (H380AnswerType::Repeat, H380Route::Repeat)
            | (H380AnswerType::Result, H380Route::WeatherLookup)
            | (H380AnswerType::Result, H380Route::TimeLookup)
            | (H380AnswerType::Clarification, H380Route::Clarification)
            | (H380AnswerType::PublicChat, H380Route::PublicChat)
    )
}

fn h380_semantic_consistency_ok(
    lower: &str,
    answer_type: H380AnswerType,
    route: H380Route,
    protected: bool,
) -> bool {
    if lower.contains("not the weather the proof") && route == H380Route::WeatherLookup {
        return false;
    }
    if lower == "repeat that" && answer_type != H380AnswerType::Repeat {
        return false;
    }
    if lower == "explain that" && answer_type == H380AnswerType::Repeat {
        return false;
    }
    if protected && route != H380Route::ProtectedFailClosed {
        return false;
    }
    true
}

fn h380_broken_language_score(lower: &str) -> u8 {
    let word_count = lower.split_whitespace().count();
    if lower.contains("time tokyo now what")
        || lower.contains("weather barcelona rain proper check")
        || lower.contains("same sydney tomorrow")
        || lower.contains("not that proof check")
        || word_count <= 3
    {
        60
    } else {
        5
    }
}

fn h380_transcript_notes(lower: &str) -> Vec<String> {
    let mut notes = Vec::new();
    if h380_broken_language_score(lower) >= 60 {
        notes.push("BROKEN_OR_CLIPPED_COMMITTED_TEXT".to_string());
    }
    if lower.contains("time time") || lower.contains("check check") {
        notes.push("REPEATED_FRAGMENT".to_string());
    }
    notes
}

fn h381_h380_live_response_text(
    packet: &H380TurnUnderstandingPacket,
    last_turn_context: Option<&LastTurnContext>,
    language_packet: Option<&LanguagePacket>,
) -> Option<String> {
    if !packet.answer_completeness_ok || !packet.semantic_consistency_ok {
        return Some(
            "Which part should I answer: the result, the proof, or the meaning?".to_string(),
        );
    }
    if packet.raw_user_text.trim_start().starts_with("???") {
        return None;
    }
    if packet.protected_fail_closed || packet.final_route == H380Route::ProtectedFailClosed {
        if !h381_h380_clear_live_protected_shadow(packet) {
            return None;
        }
        return Some(
            "I can't perform or prepare that protected business action from this turn. NO_SIMULATION_NO_AUTHORITY_NO_PROTECTED_EXECUTION."
                .to_string(),
        );
    }
    let use_chinese = language_packet.is_some_and(LanguagePacket::output_language_is_chinese);
    let Some(last_turn_context) = last_turn_context else {
        return match packet.final_route {
            H380Route::FollowupProvenance => Some(if use_chinese {
                "我没有可证明的上一轮工具或提供方查询可以引用。".to_string()
            } else {
                "I don't have a previous provider-backed result in this thread to prove."
                    .to_string()
            }),
            H380Route::FollowupMeaning => Some(if use_chinese {
                "你想让我解释哪一句或哪一个结果的意思？".to_string()
            } else {
                "What should I explain the meaning behind?".to_string()
            }),
            H380Route::Repeat => Some(if use_chinese {
                "我没有上一轮回答可以重复。".to_string()
            } else {
                "I don't have a previous answer in this thread to repeat.".to_string()
            }),
            H380Route::Clarification if packet.implied_intent_detected => {
                let location = h381_h380_primary_location(packet)?;
                Some(if use_chinese {
                    format!("你想让我查{location}的天气还是时间？")
                } else {
                    format!("Should I check the weather or the time for {location}?")
                })
            }
            _ => None,
        };
    };
    match packet.final_route {
        H380Route::FollowupProvenance => {
            let decision = H379FollowupDecision {
                primary: H379FollowupClass::ToolProvenanceQuestion,
                correction_detected: packet.correction_detected
                    || packet.negation_detected
                    || packet.contrast_detected,
            };
            Some(h379_followup_response_text(
                &decision,
                last_turn_context,
                language_packet,
            ))
        }
        H380Route::FollowupMeaning => {
            let decision = H379FollowupDecision {
                primary: H379FollowupClass::MeaningOrRephraseRequest,
                correction_detected: packet.correction_detected,
            };
            Some(h379_followup_response_text(
                &decision,
                last_turn_context,
                language_packet,
            ))
        }
        H380Route::Repeat => {
            let decision = H379FollowupDecision {
                primary: H379FollowupClass::RepeatRequest,
                correction_detected: packet.correction_detected,
            };
            Some(h379_followup_response_text(
                &decision,
                last_turn_context,
                language_packet,
            ))
        }
        _ => None,
    }
}

fn h381_h380_live_nlp_rewrite(
    packet: Option<&H380TurnUnderstandingPacket>,
    previous: Option<&LastTurnContext>,
) -> Option<String> {
    let packet = packet?;
    if packet.protected_fail_closed
        || !packet.answer_completeness_ok
        || !packet.semantic_consistency_ok
        || matches!(
            packet.final_route,
            H380Route::FollowupProvenance | H380Route::FollowupMeaning | H380Route::Repeat
        )
    {
        return None;
    }
    let location = h381_h380_primary_location(packet)?;
    if packet.final_route == H380Route::WeatherLookup {
        let lower = packet.normalized_text.as_str();
        if lower.contains("forecast") {
            return Some(format!("what is the forecast for {location}"));
        }
        if lower.contains("rain") && lower.contains("tomorrow") {
            return Some(format!("will it rain in {location} tomorrow"));
        }
        if lower.contains("rain") || packet.raw_user_text.contains("下雨") || lower.contains('雨')
        {
            return Some(format!("is it raining in {location}"));
        }
        return Some(format!("what is the weather in {location}"));
    }
    if packet.final_route == H380Route::TimeLookup {
        return Some(format!("what is the time in {location}"));
    }
    let previous = previous?;
    if !packet.implied_intent_detected {
        return None;
    }
    match previous.route_class {
        LastTurnRouteClass::ToolWeather if packet.final_route == H380Route::WeatherLookup => {
            Some(format!("what is the weather in {location}"))
        }
        LastTurnRouteClass::ToolTime if h409_weather_condition_phrase(&packet.normalized_text) => {
            Some(format!("what is the weather in {location}"))
        }
        LastTurnRouteClass::ToolTime => Some(format!("what is the time in {location}")),
        _ => None,
    }
}

fn h381_h380_primary_location(packet: &H380TurnUnderstandingPacket) -> Option<String> {
    packet
        .slots_present
        .iter()
        .find_map(|slot| slot.strip_prefix("location:"))
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn h381_h380_clear_live_protected_shadow(packet: &H380TurnUnderstandingPacket) -> bool {
    let lower = packet.normalized_text.as_str();
    lower.contains("approve payroll")
        || lower.contains("increase tim s salary")
        || lower.contains("increase tims salary")
        || lower.contains("pay him more")
        || lower.contains("fix the roster")
        || lower.contains("roster change")
        || lower.contains("send the customer refund")
        || lower.contains("change rj s commission")
        || lower.contains("delete that employee")
        || lower.contains("give her access")
        || lower.contains("approve leave")
        || lower.contains("leave approval")
        || h406_official_company_execution_request(lower)
        || packet.raw_user_text.contains("加薪")
        || packet.raw_user_text.contains("退款")
        || packet.raw_user_text.contains("排班")
}

fn h380_result_class(
    route: H380Route,
    protected: bool,
    provenance: bool,
    meaning: bool,
) -> &'static str {
    if protected {
        "PROTECTED_UNDERSTANDING_FAIL_CLOSED_PASS"
    } else if provenance {
        "CROSS_ROUTE_PROVENANCE_PASS"
    } else if meaning {
        "MEANING_BEHIND_RESPONSE_PASS"
    } else {
        match route {
            H380Route::TimeLookup | H380Route::WeatherLookup | H380Route::PublicChat => {
                "COMMITTED_TURN_UNDERSTANDING_PASS"
            }
            H380Route::Clarification => "CONFIDENCE_CLARIFICATION_PASS",
            H380Route::Repeat => "ANSWER_TYPE_CLASSIFICATION_PASS",
            H380Route::FollowupProvenance => "CROSS_ROUTE_PROVENANCE_PASS",
            H380Route::FollowupMeaning => "MEANING_BEHIND_RESPONSE_PASS",
            H380Route::ProtectedFailClosed => "PROTECTED_UNDERSTANDING_FAIL_CLOSED_PASS",
        }
    }
}

impl ReadOnlyIncidentKind {
    fn outcome_type(self) -> &'static str {
        match self {
            ReadOnlyIncidentKind::ToolFail => "READ_ONLY_TOOL_FAIL",
            ReadOnlyIncidentKind::ClarifyLoop => "READ_ONLY_CLARIFY_LOOP",
            ReadOnlyIncidentKind::UserCorrection => "READ_ONLY_USER_CORRECTION",
        }
    }

    fn tag(self) -> &'static str {
        match self {
            ReadOnlyIncidentKind::ToolFail => "tool_fail",
            ReadOnlyIncidentKind::ClarifyLoop => "clarify_loop",
            ReadOnlyIncidentKind::UserCorrection => "user_correction",
        }
    }

    fn feedback_event_type(self) -> FeedbackEventType {
        match self {
            ReadOnlyIncidentKind::ToolFail => FeedbackEventType::ToolFail,
            ReadOnlyIncidentKind::ClarifyLoop => FeedbackEventType::ClarifyLoop,
            ReadOnlyIncidentKind::UserCorrection => FeedbackEventType::UserCorrection,
        }
    }

    fn learn_signal_type(self) -> LearnSignalType {
        match self {
            ReadOnlyIncidentKind::ToolFail => LearnSignalType::ToolFail,
            ReadOnlyIncidentKind::ClarifyLoop => LearnSignalType::ClarifyLoop,
            ReadOnlyIncidentKind::UserCorrection => LearnSignalType::UserCorrection,
        }
    }

    fn severe(self) -> bool {
        matches!(
            self,
            ReadOnlyIncidentKind::ToolFail | ReadOnlyIncidentKind::ClarifyLoop
        )
    }
}

