fn packet_field_value<'a>(packet: &'a str, key: &str) -> Option<&'a str> {
    packet.split(';').find_map(|part| {
        let (candidate_key, value) = part.split_once('=')?;
        if candidate_key.trim() == key {
            let value = value.trim();
            if value.is_empty() {
                None
            } else {
                Some(value)
            }
        } else {
            None
        }
    })
}

fn packet_field_bool(packet: &str, key: &str) -> bool {
    packet_field_value(packet, key)
        .map(|value| value.eq_ignore_ascii_case("true"))
        .unwrap_or(false)
}

fn packet_field_list(packet: &str, key: &str, delimiter: char) -> Vec<String> {
    packet_field_value(packet, key)
        .filter(|value| *value != "none")
        .map(|value| {
            value
                .split(delimiter)
                .map(str::trim)
                .filter(|item| !item.is_empty() && *item != "none")
                .map(ToString::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn packet_field_value_any<'a>(packet: &'a str, keys: &[&str]) -> Option<&'a str> {
    keys.iter().find_map(|key| packet_field_value(packet, key))
}

fn packet_field_bool_any(packet: &str, keys: &[&str]) -> bool {
    packet_field_value_any(packet, keys)
        .map(|value| value.eq_ignore_ascii_case("true"))
        .unwrap_or(false)
}

fn packet_field_list_any(packet: &str, keys: &[&str], delimiter: char) -> Vec<String> {
    keys.iter()
        .find_map(|key| {
            let values = packet_field_list(packet, key, delimiter);
            if values.is_empty() {
                None
            } else {
                Some(values)
            }
        })
        .unwrap_or_default()
}

fn deep_research_field_map(
    fields: &[selene_kernel_contracts::ph1e::ToolStructuredField],
) -> BTreeMap<String, String> {
    fields
        .iter()
        .map(|field| (field.key.clone(), field.value.clone()))
        .collect()
}

fn adapter_domain_from_http_url(url: &str) -> Option<String> {
    let rest = url
        .strip_prefix("https://")
        .or_else(|| url.strip_prefix("http://"))?;
    let host_port = rest
        .split(['/', '?', '#'])
        .next()
        .unwrap_or_default()
        .trim()
        .trim_matches('.');
    if host_port.is_empty() || host_port.contains('@') {
        return None;
    }
    let domain = if host_port.starts_with('[') {
        host_port
            .split_once(']')
            .map(|(host, _)| host.trim_start_matches('[').to_string())?
    } else {
        host_port
            .split(':')
            .next()
            .map(str::to_string)
            .unwrap_or_default()
    };
    if domain.is_empty() {
        None
    } else {
        Some(domain.to_ascii_lowercase())
    }
}

fn adapter_source_link_public_http_url(url: &str) -> bool {
    let Some(domain) = adapter_domain_from_http_url(url) else {
        return false;
    };
    if !(url.starts_with("https://") || url.starts_with("http://")) {
        return false;
    }
    if domain == "localhost"
        || domain == "metadata.google.internal"
        || domain == "::1"
        || domain.starts_with("fc")
        || domain.starts_with("fd")
        || domain.starts_with("fe80")
        || domain.ends_with(".localhost")
        || domain.ends_with(".local")
    {
        return false;
    }
    let octets = domain
        .split('.')
        .map(str::parse::<u8>)
        .collect::<Result<Vec<_>, _>>()
        .unwrap_or_default();
    if octets.len() == 4 {
        return !matches!(
            octets.as_slice(),
            [0, _, _, _]
                | [10, _, _, _]
                | [127, _, _, _]
                | [169, 254, _, _]
                | [192, 168, _, _]
                | [224..=239, _, _, _]
                | [240..=255, _, _, _]
        ) && !(octets[0] == 172 && (16..=31).contains(&octets[1]))
            && !(octets[0] == 100 && (64..=127).contains(&octets[1]));
    }
    true
}

fn deep_research_limitations(image_status: &str, gdelt_status: &str) -> Vec<String> {
    let mut limitations = Vec::new();
    if image_status.contains("DEFERRED") {
        limitations.push("sourced image/photo cards deferred until a verified image metadata provider path exists".to_string());
    }
    if gdelt_status.contains("DEFERRED") {
        limitations.push(
            "GDELT live corroboration deferred until the provider is cleanly live-wired"
                .to_string(),
        );
    }
    limitations
}

fn recover_typed_public_deterministic_tool_answer(
    typed_only: bool,
    execution: &mut AppVoiceTurnExecutionOutcome,
) -> Option<String> {
    if !typed_only {
        return None;
    }
    let tool_response = execution.tool_response.as_ref()?;
    if tool_response.tool_status != ToolStatus::Ok {
        return None;
    }
    let is_public_deterministic = execution
        .ph1x_request
        .as_ref()
        .and_then(|request| request.nlp_output.as_ref())
        .is_some_and(|nlp_output| {
            matches!(
                nlp_output,
                Ph1nResponse::IntentDraft(intent)
                    if matches!(intent.intent_type, IntentType::TimeQuery | IntentType::WeatherQuery)
            )
        });
    if !is_public_deterministic {
        return None;
    }
    let Some(Ph1xResponseLike::Respond(response_text, reason_code)) =
        typed_public_deterministic_ph1x_response_summary(execution)
    else {
        return None;
    };

    execution.next_move = AppVoiceTurnNextMove::Respond;
    execution.response_text = Some(response_text.clone());
    execution.reason_code = Some(reason_code);
    Some(response_text)
}

fn apply_h406_public_presentation_adaptation_to_execution_outcome(
    user_text: Option<&str>,
    execution: &mut AppVoiceTurnExecutionOutcome,
) {
    let Some(user_text) = user_text else {
        return;
    };
    let Some(tool_response) = execution.tool_response.as_ref() else {
        return;
    };
    if tool_response.tool_status != ToolStatus::Ok {
        return;
    }
    match tool_response.tool_result.as_ref() {
        Some(ToolResult::Time { local_time_iso })
            if h406_user_requested_24_hour_time(user_text) =>
        {
            if let Some(answer) = h406_time_answer_24_hour(local_time_iso) {
                execution.response_text = Some(answer);
            }
        }
        Some(ToolResult::Weather { summary }) if h406_user_requested_short_answer(user_text) => {
            let current = execution
                .response_text
                .as_deref()
                .filter(|value| !value.trim().is_empty())
                .unwrap_or(summary);
            execution.response_text = Some(h406_short_weather_answer(current));
        }
        _ => {}
    }
}

fn h406_user_requested_24_hour_time(user_text: &str) -> bool {
    let lower = user_text.to_ascii_lowercase();
    lower.contains("24-hour")
        || lower.contains("24 hour")
        || lower.contains("24hr")
        || lower.contains("24 hr")
        || lower.contains("military time")
        || lower.contains("use 24")
}

fn h406_user_requested_short_answer(user_text: &str) -> bool {
    let lower = user_text.to_ascii_lowercase();
    lower.contains("keep it short")
        || lower.contains("short answer")
        || lower.contains("brief")
        || lower.contains("concise")
}

fn h406_time_answer_24_hour(local_time_iso: &str) -> Option<String> {
    let (time, label) = h406_time_24_hour_display_and_label(local_time_iso)?;
    if label.is_empty() {
        Some(format!("It's {time}."))
    } else {
        Some(format!("It's {time} in {label}."))
    }
}

fn h406_time_24_hour_display_and_label(local_time_iso: &str) -> Option<(String, String)> {
    let (timestamp, label) = match local_time_iso.rsplit_once('[') {
        Some((timestamp, zone_part)) => {
            let zone_and_label = zone_part.strip_suffix(']')?;
            let (zone, explicit_label) = zone_and_label
                .split_once('|')
                .map(|(zone, label)| (zone, Some(label)))
                .unwrap_or((zone_and_label, None));
            let label = explicit_label
                .map(str::trim)
                .filter(|label| !label.is_empty())
                .map(str::to_string)
                .unwrap_or_else(|| h406_time_zone_display_label(zone));
            (timestamp, label)
        }
        None => (local_time_iso, String::new()),
    };
    let time = timestamp.split_once('T')?.1;
    let hour: u32 = time.get(0..2)?.parse().ok()?;
    let minute = time.get(3..5)?;
    Some((format!("{hour:02}:{minute}"), label))
}

fn h406_time_zone_display_label(zone: &str) -> String {
    match zone {
        "America/New_York" => "New York".to_string(),
        "Asia/Tokyo" => "Japan".to_string(),
        "Australia/Sydney" => "Sydney".to_string(),
        "Europe/Berlin" => "Germany".to_string(),
        "Europe/Rome" => "Italy".to_string(),
        "Europe/Lisbon" => "Lisbon".to_string(),
        "Europe/London" => "London".to_string(),
        other => other.rsplit('/').next().unwrap_or(other).replace('_', " "),
    }
}

fn h406_short_weather_answer(answer: &str) -> String {
    let trimmed = answer.trim();
    if trimmed.chars().count() <= 120 {
        return trimmed.to_string();
    }
    if let Some((first, _)) = trimmed.split_once('.') {
        let first = first.trim();
        if !first.is_empty() {
            return format!("{first}.");
        }
    }
    trimmed
        .chars()
        .take(120)
        .collect::<String>()
        .trim()
        .to_string()
}

enum Ph1xResponseLike {
    Respond(String, ReasonCodeId),
}

fn typed_public_deterministic_ph1x_response_summary(
    execution: &AppVoiceTurnExecutionOutcome,
) -> Option<Ph1xResponseLike> {
    let response = execution.ph1x_response.as_ref()?;
    match &response.directive {
        Ph1xDirective::Respond(respond) => Some(Ph1xResponseLike::Respond(
            respond.response_text.clone(),
            response.reason_code,
        )),
        _ => None,
    }
}

fn execution_outcome_to_adapter_response(
    execution: AppVoiceTurnExecutionOutcome,
) -> VoiceTurnAdapterResponse {
    VoiceTurnAdapterResponse {
        status: "ok".to_string(),
        outcome: outcome_label(&execution).to_string(),
        session_id: execution
            .runtime_execution_envelope
            .session_id
            .map(session_id_to_string),
        turn_id: Some(execution.runtime_execution_envelope.turn_id.0),
        session_state: Some(session_state_to_api_value(execution.session_state)),
        session_attach_outcome: execution.runtime_execution_envelope.session_attach_outcome,
        failure_class: None,
        reason: voice_outcome_reason(&execution.voice_outcome),
        next_move: next_move_label(&execution).to_string(),
        response_text: execution.response_text.unwrap_or_default(),
        reason_code: execution
            .reason_code
            .map(|code| code.0.to_string())
            .unwrap_or_else(|| "0".to_string()),
        provenance: execution
            .tool_response
            .as_ref()
            .map(provenance_from_tool_response),
        deep_research: execution
            .tool_response
            .as_ref()
            .and_then(deep_research_metadata_from_tool_response),
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct H411PublicDiscourseResponse {
    response_text: String,
    reason_code: &'static str,
}

fn h411_public_discourse_scope_key(actor_user_id: &UserId, thread_key: &str) -> String {
    truncate_ascii(&format!("{}::{}", actor_user_id.as_str(), thread_key), 192)
}

fn h411_public_discourse_response(
    captured_text: &str,
    frame: &AdapterPublicDiscourseFrame,
) -> Option<H411PublicDiscourseResponse> {
    if captured_text.trim_start().starts_with("???") {
        return None;
    }
    let lower = h411_normalize_public_discourse_text(captured_text);
    if lower.trim().is_empty() {
        return None;
    }
    if h411_looks_like_protected_execution(&lower) {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "I can't perform or prepare that protected business action from this turn. NO_SIMULATION_NO_AUTHORITY_NO_PROTECTED_EXECUTION."
                    .to_string(),
            reason_code: "H411_PROTECTED_EXECUTION_FAIL_CLOSED_PRESERVED",
        });
    }

    if h411_is_translation_capability_question(&lower) {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "I can translate text you provide. Tell me the text and target language, and I'll translate it while preserving context and meaning."
                    .to_string(),
            reason_code: "H411_PUBLIC_TRANSLATION_CAPABILITY_ANSWER",
        });
    }

    if h411_is_memory_capability_question(&lower) {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "I can use context within this current conversation. Long-term memory depends on the approved memory system, so I should not claim permanent memory unless that path is enabled."
                    .to_string(),
            reason_code: "H411_PUBLIC_MEMORY_CAPABILITY_ANSWER",
        });
    }

    if lower.contains("tell me about payroll rules generally") {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "Payroll rules generally cover pay rates, tax withholding, records, leave, and compliance duties. I can discuss them at a public advisory level, but I cannot approve payroll without simulation and authority."
                    .to_string(),
            reason_code: "H411_PUBLIC_ADVISORY_ANSWER",
        });
    }

    if lower.contains("tell me about sydney tower") && lower.contains("centrepoint tower") {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "Sydney Tower and Centrepoint Tower refer to closely related Sydney landmark names. If you ask a follow-up with \"it,\" I need you to choose which one."
                    .to_string(),
            reason_code: "H411_PUBLIC_FACT_ACTIVE_ENTITY_SEED",
        });
    }

    if lower.contains("tell me about sydney tower") {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "Sydney Tower, also known as Sydney Tower Eye, is a prominent Sydney observation tower completed in 1981."
                    .to_string(),
            reason_code: "H411_PUBLIC_FACT_ACTIVE_ENTITY_SEED",
        });
    }

    if lower.contains("tell me about tamburlaine organic wines") {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "Tamburlaine Organic Wines is an Australian winery known for organic and biodynamic wines. It is associated with the Hunter Valley and Orange regions, with a public focus on sustainable vineyard practices."
                    .to_string(),
            reason_code: "H412_PUBLIC_ENTITY_ACTIVE_ENTITY_SEED",
        });
    }

    if lower.contains("tell me about") && h413_mentions_tamburlaine_entity_alias(&lower) {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "Assuming you mean Tamburlaine Organic Wines, Tamburlaine Organic Wines is an Australian winery known for organic and biodynamic wines. It is associated with the Hunter Valley and Orange regions, with a public focus on sustainable vineyard practices."
                    .to_string(),
            reason_code: "H413_NOISY_ENTITY_REPAIR_PASS",
        });
    }

    if h411_is_sydney_tallest_building_built_question(&lower) {
        return Some(H411PublicDiscourseResponse {
            response_text:
                "The tallest building in Sydney is Sydney Tower, which was completed in 1981."
                    .to_string(),
            reason_code: "H411_PUBLIC_FACT_ACTIVE_ENTITY_SEED",
        });
    }

    if h411_is_ambiguous_reference(&lower, frame) {
        return Some(H411PublicDiscourseResponse {
            response_text: h411_ambiguous_reference_clarification(frame),
            reason_code: "H411_PUBLIC_DISCOURSE_AMBIGUOUS_REFERENCE",
        });
    }

    let explicit_entity = h411_extract_single_public_entity(captured_text);
    let resolved_entity = explicit_entity
        .clone()
        .or_else(|| h411_resolve_public_reference(&lower, frame));
    if h411_is_height_question(&lower) {
        if let Some(entity) = resolved_entity {
            if entity == "Sydney Tower" {
                return Some(H411PublicDiscourseResponse {
                    response_text: "Sydney Tower is 309 meters (1,014 feet) tall.".to_string(),
                    reason_code: "H411_PUBLIC_FACT_COREFERENCE_ANSWER",
                });
            }
            return Some(H411PublicDiscourseResponse {
                response_text: format!(
                    "I can't verify the height of {entity} from reliable public sources right now."
                ),
                reason_code: "H411_PUBLIC_FACT_FOLLOWUP_SAFE_DEGRADE",
            });
        }
        return Some(H411PublicDiscourseResponse {
            response_text: "Which tower or building do you mean?".to_string(),
            reason_code: "H411_PUBLIC_DISCOURSE_REFERENCE_CLARIFY",
        });
    }

    let pending_builder_goal = frame.last_answer_goal.as_deref()
        == Some("identify_builder_or_construction_company")
        || frame
            .pending_unanswered_question
            .as_deref()
            .is_some_and(|question| {
                h411_is_builder_or_construction_company_question(
                    &h411_normalize_public_discourse_text(question),
                )
            });
    if pending_builder_goal {
        if let Some(entity) = explicit_entity.clone().or_else(|| {
            if h411_is_correction_phrase(&lower) || h411_contains_reference(&lower) {
                resolved_entity.clone()
            } else {
                None
            }
        }) {
            return Some(H411PublicDiscourseResponse {
                response_text: h411_public_builder_safe_degrade(&entity),
                reason_code: "H411_PUBLIC_FACT_FOLLOWUP_SAFE_DEGRADE",
            });
        }
    }
    let builder_goal = h411_is_builder_or_construction_company_question(&lower)
        || (h411_is_correction_phrase(&lower)
            && frame.last_answer_goal.as_deref()
                == Some("identify_builder_or_construction_company"));

    if builder_goal {
        if let Some(entity) = resolved_entity {
            return Some(H411PublicDiscourseResponse {
                response_text: h411_public_builder_safe_degrade(&entity),
                reason_code: "H411_PUBLIC_FACT_FOLLOWUP_SAFE_DEGRADE",
            });
        }
        return Some(H411PublicDiscourseResponse {
            response_text: "Which building or tower do you mean?".to_string(),
            reason_code: "H411_PUBLIC_DISCOURSE_REFERENCE_CLARIFY",
        });
    }

    None
}

fn h411_update_public_discourse_frame(
    frame: &mut AdapterPublicDiscourseFrame,
    captured_text: &str,
    response_text: &str,
    route_label: Option<&str>,
) {
    let captured_trimmed = captured_text.trim();
    let response_trimmed = response_text.trim();
    if !captured_trimmed.is_empty() {
        frame.last_user_question = Some(truncate_text_chars(captured_trimmed, 512));
    }
    if !response_trimmed.is_empty() {
        frame.last_assistant_answer = Some(truncate_text_chars(response_trimmed, 512));
    }
    if let Some(route) = route_label.map(str::trim).filter(|route| !route.is_empty()) {
        frame.last_public_tool_route = Some(truncate_ascii(route, 64));
    }

    let lower = h411_normalize_public_discourse_text(captured_text);
    let entities = h411_extract_public_entities(captured_text, response_text);
    if !entities.is_empty() {
        frame.active_entities = entities.clone();
        if entities.len() == 1 {
            frame.active_entity = entities.first().cloned();
            frame.current_topic = frame.active_entity.clone();
        } else {
            frame.active_entity = None;
            frame.current_topic = Some(entities.join(" / "));
        }
    }

    if let Some(goal) = h411_answer_goal_from_text(&lower) {
        frame.last_answer_goal = Some(goal.to_string());
        if goal != "identify_builder_or_construction_company" {
            frame.pending_unanswered_question = None;
        }
    }

    if h411_contains_reference(&lower) {
        frame.referenced_entity = h411_extract_single_public_entity(captured_text)
            .or_else(|| h411_resolve_public_reference(&lower, frame));
        frame.coreference_resolution = frame
            .referenced_entity
            .as_ref()
            .map(|entity| format!("resolved_reference={entity}"));
    }

    if h411_is_correction_phrase(&lower) {
        frame.correction_state = Some("correction_or_missed_question_recovery".to_string());
    } else {
        frame.correction_state = None;
    }

    if h411_is_builder_or_construction_company_question(&lower) {
        frame.pending_unanswered_question = if h411_response_answers_or_safe_degrades(response_text)
        {
            None
        } else {
            Some(truncate_text_chars(captured_trimmed, 512))
        };
        frame.last_answer_goal = Some("identify_builder_or_construction_company".to_string());
    } else if h411_is_correction_phrase(&lower)
        && frame.last_answer_goal.as_deref() == Some("identify_builder_or_construction_company")
        && h411_response_answers_or_safe_degrades(response_text)
    {
        frame.pending_unanswered_question = None;
    }
}

fn h411_normalize_public_discourse_text(text: &str) -> String {
    text.to_ascii_lowercase()
        .replace('\u{2019}', "'")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .trim_matches(|ch: char| ch.is_ascii_punctuation() || ch.is_whitespace())
        .to_string()
}

fn h411_extract_public_entities(captured_text: &str, response_text: &str) -> Vec<String> {
    let mut entities = Vec::new();
    let combined = format!("{captured_text}\n{response_text}");
    let lower = combined.to_ascii_lowercase();
    if lower.contains("sydney tower") || lower.contains("tallest building in sydney") {
        entities.push("Sydney Tower".to_string());
    }
    if lower.contains("centrepoint tower") || lower.contains("centerpoint tower") {
        entities.push("Centrepoint Tower".to_string());
    }
    if lower.contains("tamburlaine organic wines")
        || lower.contains("tumblin wines")
        || lower.contains("tumbling wines")
        || lower.contains("tumba lane organic wines")
        || h413_mentions_tamburlaine_entity_alias(&lower)
    {
        entities.push("Tamburlaine Organic Wines".to_string());
    }
    entities.sort();
    entities.dedup();
    entities
}

fn h413_mentions_tamburlaine_entity_alias(lower: &str) -> bool {
    lower.contains("tamburlaine organic wines")
        || lower.contains("tamberlane organic wines")
        || lower.contains("tumblin wines")
        || lower.contains("tumbling wines")
        || lower.contains("tumba lane organic wines")
        || lower.contains("tumblaine organic wines")
        || lower.contains("tamburlane organic wines")
        || (lower.contains("timberlain") && lower.contains("organic") && lower.contains("wine"))
        || (lower.contains("chamberlain") && lower.contains("organic") && lower.contains("wine"))
}

fn h411_extract_single_public_entity(text: &str) -> Option<String> {
    let entities = h411_extract_public_entities(text, "");
    if entities.len() == 1 {
        entities.into_iter().next()
    } else {
        None
    }
}

fn h411_answer_goal_from_text(lower: &str) -> Option<&'static str> {
    if h411_is_builder_or_construction_company_question(lower) {
        Some("identify_builder_or_construction_company")
    } else if h411_is_height_question(lower) {
        Some("answer_height")
    } else if lower.contains("when was") || lower.contains("built") || lower.contains("completed") {
        Some("answer_build_or_completion_date")
    } else {
        None
    }
}

fn h411_is_sydney_tallest_building_built_question(lower: &str) -> bool {
    lower.contains("tallest building in sydney")
        && (lower.contains("when was") || lower.contains("built") || lower.contains("completed"))
}

fn h411_is_builder_or_construction_company_question(lower: &str) -> bool {
    (lower.contains("construction company")
        || lower.contains("who built")
        || lower.contains("built it"))
        && (lower.contains("who") || lower.contains("company") || lower.contains("construction"))
}

fn h411_is_height_question(lower: &str) -> bool {
    lower.contains("how tall") || lower.contains("height")
}

fn h411_is_memory_capability_question(lower: &str) -> bool {
    lower.contains("how's your memory")
        || lower.contains("hows your memory")
        || (lower.contains("can you remember") && lower.contains("long time"))
        || (lower.contains("remember things") && lower.contains("long time"))
}

fn h411_is_translation_capability_question(lower: &str) -> bool {
    lower.contains("why can't you actually translate")
        || lower.contains("why cant you actually translate")
        || lower.contains("can you translate")
        || lower.contains("actually translate")
}

fn h411_is_correction_phrase(lower: &str) -> bool {
    lower.starts_with("i asked")
        || lower.starts_with("we talked about")
        || lower.starts_with("i mean")
        || lower.starts_with("that's not what i asked")
        || lower.starts_with("thats not what i asked")
        || lower.contains("not what i asked")
}

fn h411_contains_reference(lower: &str) -> bool {
    lower.contains(" it")
        || lower.starts_with("it ")
        || lower.contains(" that")
        || lower.contains(" this")
        || lower.contains(" the tower")
        || lower.contains(" the building")
        || lower.contains(" the company")
}

fn h411_resolve_public_reference(
    lower: &str,
    frame: &AdapterPublicDiscourseFrame,
) -> Option<String> {
    if !h411_contains_reference(lower) && !h411_is_correction_phrase(lower) {
        return None;
    }
    frame
        .active_entity
        .clone()
        .or_else(|| {
            if frame.active_entities.len() == 1 {
                frame.active_entities.first().cloned()
            } else {
                None
            }
        })
        .or_else(|| frame.referenced_entity.clone())
}

fn h411_is_ambiguous_reference(lower: &str, frame: &AdapterPublicDiscourseFrame) -> bool {
    h411_contains_reference(lower)
        && frame.active_entity.is_none()
        && frame.active_entities.len() > 1
}

fn h411_ambiguous_reference_clarification(frame: &AdapterPublicDiscourseFrame) -> String {
    let options = frame
        .active_entities
        .iter()
        .take(3)
        .cloned()
        .collect::<Vec<_>>();
    match options.as_slice() {
        [one, two] => format!("Do you mean {one} or {two}?"),
        [one] => format!("Do you mean {one}?"),
        _ => "Which one do you mean?".to_string(),
    }
}

fn h411_public_builder_safe_degrade(entity: &str) -> String {
    format!(
        "I can't verify the construction company that built {entity} from reliable public sources right now."
    )
}

fn h411_response_answers_or_safe_degrades(response_text: &str) -> bool {
    let lower = response_text.to_ascii_lowercase();
    lower.contains("can't verify")
        || lower.contains("couldn't verify")
        || lower.contains("construction company")
        || lower.contains("built")
        || lower.contains("309 meters")
}

fn h411_looks_like_protected_execution(lower: &str) -> bool {
    (lower.contains("approve") && lower.contains("payroll"))
        || (lower.contains("approve") && lower.contains("tim"))
        || lower.contains("increase tim's salary")
        || lower.contains("increase tims salary")
        || lower.contains("update the company records")
        || lower.contains("update company records")
        || lower.contains("change access")
        || lower.contains("salary")
        || lower.contains("leave approval")
        || lower.contains("database")
}

fn h410_public_brain_trace_enabled() -> bool {
    parse_bool_env("SELENE_PUBLIC_BRAIN_TRACE_ENABLED", false)
}

fn h410_public_brain_trace_raw_text_enabled() -> bool {
    parse_bool_env("SELENE_PUBLIC_BRAIN_TRACE_RAW_TEXT_ENABLED", false)
}

fn h410_public_brain_trace_max_entries() -> usize {
    (parse_u64_env("SELENE_PUBLIC_BRAIN_TRACE_MAX_ENTRIES", 128) as usize).clamp(1, 1_024)
}

fn h410_hash_text(value: &str) -> String {
    sha256_hex_for_build1c(value)
}

fn h410_trace_text(value: Option<&str>, include_raw: bool) -> (Option<String>, Option<String>) {
    let value = value.map(str::trim).filter(|value| !value.is_empty());
    (
        value.map(h410_hash_text),
        value
            .filter(|_| include_raw)
            .map(|value| truncate_text_chars(value, 512)),
    )
}

fn h410_intent_type_label(output: Option<&Ph1nResponse>) -> Option<String> {
    match output {
        Some(Ph1nResponse::IntentDraft(intent)) => Some(format!("{:?}", intent.intent_type)),
        Some(Ph1nResponse::Chat(_)) => Some("PublicChat".to_string()),
        Some(Ph1nResponse::Clarify(_)) => Some("Clarify".to_string()),
        None => None,
    }
}

fn h410_tool_route_from_nlp_output(output: Option<&Ph1nResponse>) -> Option<String> {
    match output {
        Some(Ph1nResponse::IntentDraft(intent)) => Some(format!("{:?}", intent.intent_type)),
        _ => None,
    }
}

fn h410_search_query_from_nlp_output(output: Option<&Ph1nResponse>) -> Option<String> {
    let Some(Ph1nResponse::IntentDraft(intent)) = output else {
        return None;
    };
    if !matches!(
        intent.intent_type,
        IntentType::WebSearchQuery | IntentType::NewsQuery | IntentType::DeepResearchQuery
    ) {
        return None;
    }
    intent.fields.iter().find_map(|field| {
        if field.key != FieldKey::Task {
            return None;
        }
        field
            .value
            .normalized_value
            .clone()
            .or_else(|| Some(field.value.original_span.clone()))
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
    })
}

fn h410_source_summary(
    source: &selene_kernel_contracts::ph1e::SourceRef,
    include_raw: bool,
) -> PublicBrainTraceSourceSummary {
    PublicBrainTraceSourceSummary {
        title_sha256: h410_hash_text(&source.title),
        title_text: include_raw.then(|| truncate_text_chars(&source.title, 256)),
        url_sha256: Some(h410_hash_text(&source.url)),
    }
}

fn h410_tamburlaine_ceo_safe_degrade(answer: &str) -> bool {
    let lower = answer.to_ascii_lowercase();
    lower.contains("couldn't verify")
        && lower.contains("publicly listed ceo")
        && lower.contains("tamburlaine organic wines")
}

fn h414_tamburlaine_direct_leadership_answer(answer: &str) -> bool {
    let lower = answer.to_ascii_lowercase();
    lower.contains("tamburlaine organic wines")
        && lower.contains("mark davidson")
        && lower.contains("managing director")
        && lower.contains("not the same as a verified ceo")
}

fn h414_source_accepted_for_tamburlaine_leadership(
    source: &selene_kernel_contracts::ph1e::SourceRef,
) -> bool {
    let title = source.title.to_ascii_lowercase();
    let url = source.url.to_ascii_lowercase();
    (title.contains("tamburlaine") || url.contains("tamburlaine"))
        && url.contains("tamburlaine.com.au")
}

fn h410_source_rejected_for_tamburlaine_ceo(
    source: &selene_kernel_contracts::ph1e::SourceRef,
) -> bool {
    let title = source.title.to_ascii_lowercase();
    let url = source.url.to_ascii_lowercase();
    (title.contains("wine australia") || url.contains("wineaustralia"))
        || title.contains("ceorankings")
        || url.contains("ceorankings.com")
        || (!title.contains("tamburlaine") && !url.contains("tamburlaine"))
}

fn h410_source_trace_summaries(
    tool_response: Option<&ToolResponse>,
    answer_text: &str,
    include_raw: bool,
) -> (
    Vec<PublicBrainTraceSourceSummary>,
    Vec<PublicBrainTraceSourceSummary>,
) {
    let sources = tool_response
        .and_then(|response| response.source_metadata.as_ref())
        .map(|metadata| metadata.sources.as_slice())
        .unwrap_or(&[]);
    if h414_tamburlaine_direct_leadership_answer(answer_text) {
        let accepted = sources
            .iter()
            .filter(|source| h414_source_accepted_for_tamburlaine_leadership(source))
            .map(|source| h410_source_summary(source, include_raw))
            .collect::<Vec<_>>();
        let rejected = sources
            .iter()
            .filter(|source| h410_source_rejected_for_tamburlaine_ceo(source))
            .map(|source| h410_source_summary(source, include_raw))
            .collect::<Vec<_>>();
        return (accepted, rejected);
    }
    if h410_tamburlaine_ceo_safe_degrade(answer_text) {
        let rejected = sources
            .iter()
            .filter(|source| h410_source_rejected_for_tamburlaine_ceo(source))
            .map(|source| h410_source_summary(source, include_raw))
            .collect::<Vec<_>>();
        return (Vec::new(), rejected);
    }
    let accepted = sources
        .iter()
        .map(|source| h410_source_summary(source, include_raw))
        .collect::<Vec<_>>();
    (accepted, Vec::new())
}

fn h410_engine_layer_responsible(
    packet: Option<&H380TurnUnderstandingPacket>,
    tool_response: Option<&ToolResponse>,
    rejected_sources_count: usize,
    protected_fail_closed: bool,
) -> String {
    if protected_fail_closed {
        return "DETERMINISTIC_PROTECTED_EXECUTION_GATE".to_string();
    }
    if rejected_sources_count > 0 {
        return "PH1.E_SEARCH_VERIFIER".to_string();
    }
    if packet.is_some_and(|p| p.referenced_tool_route.is_some()) {
        return "PH1.X_CONTEXT_ROUTER".to_string();
    }
    if tool_response.is_some() {
        return "PH1.E_TOOL_OR_SEARCH".to_string();
    }
    if packet.is_some() {
        return "PH1.N_PUBLIC_UNDERSTANDING".to_string();
    }
    "ADAPTER_PUBLIC_ANSWER".to_string()
}

fn h410_build_public_brain_trace(
    request: &VoiceTurnAdapterRequest,
    captured_text: Option<&str>,
    h380_packet: Option<&H380TurnUnderstandingPacket>,
    nlp_output: Option<&Ph1nResponse>,
    execution: Option<&AppVoiceTurnExecutionOutcome>,
    response_text: &str,
    discourse_frame: Option<&AdapterPublicDiscourseFrame>,
) -> Option<PublicBrainTraceRow> {
    if !h410_public_brain_trace_enabled() {
        return None;
    }
    let include_raw = h410_public_brain_trace_raw_text_enabled();
    let normalized_text = h380_packet.map(|packet| packet.normalized_text.as_str());
    let (captured_input_sha256, captured_input_text) = h410_trace_text(captured_text, include_raw);
    let (normalized_input_sha256, normalized_input_text) =
        h410_trace_text(normalized_text, include_raw);
    let search_query = h410_search_query_from_nlp_output(nlp_output);
    let (search_query_sha256, search_query_text) =
        h410_trace_text(search_query.as_deref(), include_raw);
    let tool_response = execution.and_then(|outcome| outcome.tool_response.as_ref());
    let (sources_accepted, sources_rejected) =
        h410_source_trace_summaries(tool_response, response_text, include_raw);
    let protected_fail_closed = h380_packet.is_some_and(|packet| packet.protected_fail_closed)
        || response_text.contains("NO_SIMULATION_NO_AUTHORITY_NO_PROTECTED_EXECUTION");
    let protected_execution_attempted =
        protected_fail_closed || h380_packet.is_some_and(|packet| packet.protected_fail_closed);
    let failure_reason = if h410_tamburlaine_ceo_safe_degrade(response_text) {
        Some("UNVERIFIED_ENTITY_ANSWER_SAFE_DEGRADE".to_string())
    } else if protected_fail_closed {
        Some("NO_SIMULATION_NO_EXECUTION_PROTECTED_ONLY".to_string())
    } else {
        execution.and_then(|outcome| outcome.reason_code.map(|code| code.0.to_string()))
    };
    let engine_layer_responsible = h410_engine_layer_responsible(
        h380_packet,
        tool_response,
        sources_rejected.len(),
        protected_fail_closed,
    );
    let final_answer_sha256 = h410_hash_text(response_text);
    Some(PublicBrainTraceRow {
        schema_version: 1,
        result_class: "H410_PUBLIC_BRAIN_BLACK_BOX_TRACE_PASS".to_string(),
        trace_id: format!("h410:{}:{}", request.correlation_id, request.turn_id),
        correlation_id: request.correlation_id,
        turn_id: request.turn_id,
        diagnostic_mode: if include_raw {
            "dev_raw_text".to_string()
        } else {
            "metadata_hash_only".to_string()
        },
        raw_text_included: include_raw,
        raw_audio_retained: false,
        captured_input_sha256,
        captured_input_text,
        normalized_input_sha256,
        normalized_input_text,
        language_detected: h380_packet.map(|packet| packet.detected_language.clone()),
        dominant_language: h380_packet.map(|packet| packet.dominant_language.clone()),
        intent_chosen: h380_packet
            .map(|packet| format!("{:?}", packet.primary_intent))
            .or_else(|| h410_intent_type_label(nlp_output)),
        context_used: h380_packet.is_some_and(|packet| {
            packet.referenced_previous_turn
                || packet.referenced_previous_answer
                || packet.referenced_tool_route.is_some()
        }) || discourse_frame.is_some_and(h411_public_discourse_frame_used),
        context_route_used: h380_packet
            .and_then(|packet| packet.referenced_tool_route)
            .map(|route| format!("{:?}", route)),
        tool_route_selected: h380_packet
            .map(|packet| packet.final_route.as_str().to_string())
            .or_else(|| h410_tool_route_from_nlp_output(nlp_output)),
        search_query_sha256,
        search_query_text,
        sources_accepted_count: sources_accepted.len(),
        sources_rejected_count: sources_rejected.len(),
        sources_accepted,
        sources_rejected,
        final_answer_sha256: final_answer_sha256.clone(),
        formatter_output_sha256: final_answer_sha256,
        tts_input_text_sha256: None,
        protected_execution_attempted,
        protected_fail_closed,
        failure_reason,
        engine_layer_responsible,
        active_entity: discourse_frame.and_then(|frame| frame.active_entity.clone()),
        pending_question: discourse_frame
            .and_then(|frame| frame.pending_unanswered_question.clone()),
        answer_goal: discourse_frame.and_then(|frame| frame.last_answer_goal.clone()),
        correction_state: discourse_frame.and_then(|frame| frame.correction_state.clone()),
        coreference_resolution: discourse_frame
            .and_then(|frame| frame.coreference_resolution.clone()),
    })
}

fn h411_public_discourse_frame_used(frame: &AdapterPublicDiscourseFrame) -> bool {
    frame.active_entity.is_some()
        || !frame.active_entities.is_empty()
        || frame.pending_unanswered_question.is_some()
        || frame.last_answer_goal.is_some()
        || frame.referenced_entity.is_some()
        || frame.correction_state.is_some()
        || frame.coreference_resolution.is_some()
}

fn execution_outcome_is_public_no_intent(execution: &AppVoiceTurnExecutionOutcome) -> bool {
    if execution.tool_response.is_some() {
        return false;
    }
    let response_text_is_no_intent = execution
        .response_text
        .as_deref()
        .map(str::trim)
        .is_some_and(|text| text == "Okay. What would you like to do?");
    let ph1x_request_is_no_intent = execution
        .ph1x_request
        .as_ref()
        .is_some_and(ph1x_request_is_public_no_intent_chat);
    let directive_is_plain_response = execution
        .ph1x_response
        .as_ref()
        .is_some_and(|response| matches!(response.directive, Ph1xDirective::Respond(_)));
    directive_is_plain_response && (response_text_is_no_intent || ph1x_request_is_no_intent)
}

fn ph1x_request_is_public_no_intent_chat(
    request: &selene_kernel_contracts::ph1x::Ph1xRequest,
) -> bool {
    if request.policy_context_ref.privacy_mode
        || request.policy_context_ref.do_not_disturb
        || request.policy_context_ref.safety_tier != SafetyTier::Standard
    {
        return false;
    }
    matches!(
        request.nlp_output.as_ref(),
        Some(Ph1nResponse::Chat(chat))
            if chat.reason_code == ph1n_reason_codes::N_CHAT_NO_INTENT
    )
}

fn sanitize_transcript_text_option(value: Option<String>) -> Option<String> {
    value
        .map(|v| truncate_ascii(v.trim(), 8192))
        .filter(|v| !v.trim().is_empty())
}

fn user_text_looks_like_correction(text: &str) -> bool {
    let normalized = text.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        return false;
    }
    const PREFIXES: [&str; 8] = [
        "no ",
        "no,",
        "actually",
        "i meant",
        "sorry, i meant",
        "let me correct",
        "correction:",
        "that's not",
    ];
    if PREFIXES.iter().any(|prefix| normalized.starts_with(prefix)) {
        return true;
    }
    normalized.contains(" i meant ")
        || normalized.contains(" correction ")
        || normalized.contains(" not that")
}

fn infer_confirm_answer_from_user_text(
    thread_state: &ThreadState,
    user_text_final: Option<&str>,
) -> Option<ConfirmAnswer> {
    let awaiting_confirm = thread_state.return_check_pending
        || matches!(
            thread_state.pending.as_ref(),
            Some(PendingState::Confirm { .. } | PendingState::MemoryPermission { .. })
        );
    if !awaiting_confirm {
        return None;
    }

    let normalized = user_text_final?.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        return None;
    }

    const YES_EXACT: [&str; 8] = [
        "yes", "y", "yeah", "yep", "confirm", "correct", "ok", "okay",
    ];
    const NO_EXACT: [&str; 7] = ["no", "n", "nope", "nah", "cancel", "stop", "don't"];
    const YES_PREFIXES: [&str; 4] = ["yes,", "yes.", "confirm,", "confirm."];
    const NO_PREFIXES: [&str; 3] = ["no,", "no.", "cancel,"];

    if YES_EXACT.contains(&normalized.as_str())
        || YES_PREFIXES
            .iter()
            .any(|prefix| normalized.starts_with(prefix))
    {
        return Some(ConfirmAnswer::Yes);
    }
    if NO_EXACT.contains(&normalized.as_str())
        || NO_PREFIXES
            .iter()
            .any(|prefix| normalized.starts_with(prefix))
    {
        return Some(ConfirmAnswer::No);
    }
    None
}

fn adapter_transcript_role_from_storage(role: ConversationRole) -> AdapterTranscriptRole {
    match role {
        ConversationRole::User => AdapterTranscriptRole::User,
        ConversationRole::Selene => AdapterTranscriptRole::Selene,
    }
}

fn adapter_transcript_source_from_storage(
    source: ConversationSource,
) -> Option<AdapterTranscriptSource> {
    match source {
        ConversationSource::VoiceTranscript => Some(AdapterTranscriptSource::Ph1C),
        ConversationSource::SeleneOutput => Some(AdapterTranscriptSource::Ph1Write),
        ConversationSource::TypedText => Some(AdapterTranscriptSource::UiText),
        ConversationSource::Tombstone => None,
    }
}

fn adapter_transcript_event_from_record(
    record: &selene_kernel_contracts::ph1f::ConversationTurnRecord,
) -> Option<AdapterTranscriptEvent> {
    let source = adapter_transcript_source_from_storage(record.source)?;
    Some(AdapterTranscriptEvent {
        seq: record.conversation_turn_id.0,
        correlation_id: record.correlation_id,
        turn_id: record.turn_id,
        role: adapter_transcript_role_from_storage(record.role),
        source,
        finalized: true,
        text: record.text.clone(),
        timestamp_ns: record.created_at.0,
    })
}

#[allow(clippy::too_many_arguments)]
fn append_transcript_final_conversation_turn(
    store: &mut Ph1fStore,
    now: MonotonicTimeNs,
    correlation_id: CorrelationId,
    turn_id: TurnId,
    actor_user_id: &UserId,
    device_id: Option<&DeviceId>,
    session_id: Option<SessionId>,
    role: ConversationRole,
    source: ConversationSource,
    text: &str,
) -> Result<(), String> {
    let text = truncate_ascii(text.trim(), 8192);
    if text.is_empty() {
        return Ok(());
    }
    let idempotency_key = sanitize_idempotency_token(&format!(
        "adapter_transcript:{}:{}:{}:{}",
        correlation_id.0,
        turn_id.0,
        match role {
            ConversationRole::User => "USER",
            ConversationRole::Selene => "SELENE",
        },
        match source {
            ConversationSource::VoiceTranscript => "PH1.C",
            ConversationSource::TypedText => "UI.TEXT",
            ConversationSource::SeleneOutput => "PH1.WRITE",
            ConversationSource::Tombstone => "TOMBSTONE",
        }
    ));
    let input = ConversationTurnInput::v1(
        now,
        correlation_id,
        turn_id,
        session_id,
        actor_user_id.clone(),
        device_id.cloned(),
        role,
        source,
        text.clone(),
        stable_hash_hex_16(&text),
        PrivacyScope::PublicChat,
        Some(idempotency_key),
        None,
        None,
    )
    .map_err(|err| format!("invalid transcript conversation input: {err:?}"))?;
    let _ = store
        .append_conversation_turn(input)
        .map_err(storage_error_to_string)?;
    Ok(())
}

fn storage_error_to_string(err: StorageError) -> String {
    format!("{err:?}")
}

fn snapshot_sync_queue_counters(
    store: &Ph1fStore,
    now: MonotonicTimeNs,
) -> AdapterSyncQueueCounters {
    let mut counters = AdapterSyncQueueCounters::default();
    for row in store.device_artifact_sync_queue_rows() {
        match row.state {
            MobileArtifactSyncState::Queued => {
                counters.queued_count = counters.queued_count.saturating_add(1);
            }
            MobileArtifactSyncState::InFlight => {
                counters.in_flight_count = counters.in_flight_count.saturating_add(1);
                if row.last_error.is_some() {
                    counters.retry_pending_count = counters.retry_pending_count.saturating_add(1);
                }
            }
            MobileArtifactSyncState::Acked => {
                counters.acked_count = counters.acked_count.saturating_add(1);
            }
            MobileArtifactSyncState::DeadLetter => {
                counters.dead_letter_count = counters.dead_letter_count.saturating_add(1);
            }
        }
    }
    counters.replay_due_count = store.device_artifact_sync_replay_due_rows(now).len() as u32;
    counters
}

fn collect_sync_issue_records_for_pass(
    store: &Ph1fStore,
    now: MonotonicTimeNs,
    queue_after: &AdapterSyncQueueCounters,
) -> Vec<SyncIssueRecord> {
    let mut out = Vec::new();
    for row in store.device_artifact_sync_queue_rows() {
        let attempted_this_pass = row.last_attempted_at == Some(now);
        if attempted_this_pass && row.state == MobileArtifactSyncState::DeadLetter {
            out.push(SyncIssueRecord {
                issue_kind: SyncIssueKind::DeadLetter,
                sync_job_id: row.sync_job_id.clone(),
                sync_kind: row.sync_kind,
                attempt_count: row.attempt_count,
                last_error: row.last_error.clone(),
                user_id: row.user_id.clone(),
                device_id: row.device_id.clone(),
            });
            continue;
        }
        if attempted_this_pass && row.last_error.is_some() {
            out.push(SyncIssueRecord {
                issue_kind: SyncIssueKind::Retry,
                sync_job_id: row.sync_job_id.clone(),
                sync_kind: row.sync_kind,
                attempt_count: row.attempt_count,
                last_error: row.last_error.clone(),
                user_id: row.user_id.clone(),
                device_id: row.device_id.clone(),
            });
        }
    }
    if queue_after.replay_due_count > 0 {
        out.push(SyncIssueRecord {
            issue_kind: SyncIssueKind::ReplayDue,
            sync_job_id: "queue_replay_due".to_string(),
            sync_kind: MobileArtifactSyncKind::VoiceProfile,
            attempt_count: queue_after.replay_due_count as u16,
            last_error: Some("replay_due".to_string()),
            user_id: None,
            device_id: DeviceId::new("adapter_sync_aggregate_device")
                .expect("static aggregate device id must be valid"),
        });
    }
    out
}

fn sync_issue_tag(kind: SyncIssueKind) -> &'static str {
    match kind {
        SyncIssueKind::Retry => "RETRY",
        SyncIssueKind::DeadLetter => "DEADLETTER",
        SyncIssueKind::ReplayDue => "REPLAY_DUE",
    }
}

fn sync_issue_latency_ms(kind: SyncIssueKind) -> u32 {
    match kind {
        SyncIssueKind::Retry => 100,
        SyncIssueKind::DeadLetter => 250,
        SyncIssueKind::ReplayDue => 500,
    }
}

fn artifact_type_for_sync_issue(kind: SyncIssueKind) -> ArtifactType {
    match kind {
        SyncIssueKind::Retry => ArtifactType::VoiceIdProfileDeltaPack,
        SyncIssueKind::DeadLetter => ArtifactType::VoiceIdProfileDeltaPack,
        SyncIssueKind::ReplayDue => ArtifactType::VoiceIdThresholdPack,
    }
}

fn tenant_scope_from_user_id(user_id: &UserId) -> Option<&str> {
    let (tenant_scope, _) = user_id.as_str().split_once(':')?;
    if tenant_scope.trim().is_empty() {
        return None;
    }
    Some(tenant_scope)
}

fn sanitize_idempotency_token(value: &str) -> String {
    let mut out = String::with_capacity(value.len());
    for c in value.chars() {
        if c.is_ascii_alphanumeric() || matches!(c, '_' | '-' | '.') {
            out.push(c);
        } else {
            out.push('_');
        }
    }
    if out.is_empty() {
        "sync_idem".to_string()
    } else {
        truncate_ascii(&out, 128)
    }
}

fn resolve_adapter_thread_key(value: Option<&str>) -> String {
    let raw = value
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .unwrap_or("default");
    let mut out = String::with_capacity(raw.len());
    for c in raw.chars() {
        if c.is_ascii_alphanumeric() || matches!(c, '_' | '-' | '.') {
            out.push(c);
        } else {
            out.push('_');
        }
    }
    if out.is_empty() {
        "default".to_string()
    } else {
        truncate_ascii(&out, 96)
    }
}

fn resolve_adapter_project_id(value: Option<&str>) -> Option<String> {
    let raw = value.map(str::trim).filter(|v| !v.is_empty())?;
    let mut out = String::with_capacity(raw.len());
    for c in raw.chars() {
        if c.is_ascii_alphanumeric() || matches!(c, '_' | '-' | '.' | ':' | '/') {
            out.push(c);
        } else {
            out.push('_');
        }
    }
    if out.is_empty() {
        None
    } else {
        Some(truncate_ascii(&out, 96))
    }
}

fn resolve_adapter_pinned_context_refs(values: Option<&[String]>) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    let Some(values) = values else {
        return out;
    };
    for value in values {
        let raw = value.trim();
        if raw.is_empty() {
            continue;
        }
        let mut normalized = String::with_capacity(raw.len());
        for c in raw.chars() {
            if c.is_ascii_alphanumeric() || matches!(c, '_' | '-' | '.' | ':' | '/') {
                normalized.push(c);
            } else {
                normalized.push('_');
            }
        }
        let normalized = truncate_ascii(&normalized, 128);
        if normalized.is_empty() || out.iter().any(|existing| existing == &normalized) {
            continue;
        }
        out.push(normalized);
        if out.len() >= 16 {
            break;
        }
    }
    out
}

