    fn spawn_openai_responses_endpoint_for_public_answer_test(output_text: &'static str) -> String {
        spawn_openai_responses_endpoint_for_public_answer_sequence(vec![output_text])
    }

    fn spawn_openai_responses_endpoint_for_public_answer_sequence(
        output_texts: Vec<&'static str>,
    ) -> String {
        use std::io::{Read, Write};

        let listener = std::net::TcpListener::bind("127.0.0.1:0")
            .expect("mock OpenAI responses listener should bind");
        let address = listener.local_addr().expect("mock OpenAI address");
        std::thread::spawn(move || {
            for output_text in output_texts {
                let Ok((mut stream, _)) = listener.accept() else {
                    return;
                };
                let mut request_buffer = [0_u8; 4096];
                let _ = stream.read(&mut request_buffer);
                let body = serde_json::json!({ "output_text": output_text }).to_string();
                let response = format!(
                    "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                    body.len(),
                    body
                );
                let _ = stream.write_all(response.as_bytes());
            }
        });
        format!("http://{address}/v1/responses")
    }

    fn ph1d_public_no_intent_test_outcome(response_text: &str) -> AppVoiceTurnExecutionOutcome {
        let runtime_execution_envelope = RuntimeExecutionEnvelope::v1(
            "ph1d_public_no_intent_request".to_string(),
            "trace:ph1d_public_no_intent".to_string(),
            "idem:ph1d_public_no_intent".to_string(),
            UserId::new("tenant_1:ph1d_public_no_intent_actor").unwrap(),
            DeviceId::new("ph1d_public_no_intent_device").unwrap(),
            AppPlatform::Desktop,
            None,
            TurnId(1),
            AdmissionState::IngressValidated,
        )
        .unwrap();
        let ph1x_response = selene_kernel_contracts::ph1x::Ph1xResponse::v1(
            1,
            1,
            Ph1xDirective::Respond(
                selene_kernel_contracts::ph1x::RespondDirective::v1(response_text.to_string())
                    .unwrap(),
            ),
            ThreadState::empty_v1(),
            None,
            selene_kernel_contracts::ph1x::DeliveryHint::AudibleAndText,
            ReasonCodeId(1),
            Some("ph1d_public_no_intent".to_string()),
        )
        .unwrap();
        AppVoiceTurnExecutionOutcome {
            runtime_execution_envelope,
            voice_outcome: OsVoiceLiveTurnOutcome::NotInvokedDisabled,
            session_state: SessionState::Active,
            next_move: AppVoiceTurnNextMove::Respond,
            ph1x_request: None,
            ph1x_response: Some(ph1x_response),
            dispatch_outcome: None,
            tool_response: None,
            response_text: Some(response_text.to_string()),
            reason_code: Some(ReasonCodeId(1)),
        }
    }

    fn run_public_prompt_with_mock_answer(prompt: &str, output_text: &'static str) -> String {
        run_public_prompt_sequence_with_mock_answers(&[(prompt, output_text)])
            .into_iter()
            .next()
            .expect("single public answer should be returned")
    }

    fn run_public_prompt_sequence_with_mock_answers(cases: &[(&str, &'static str)]) -> Vec<String> {
        let endpoint = spawn_openai_responses_endpoint_for_public_answer_sequence(
            cases.iter().map(|(_, output_text)| *output_text).collect(),
        );
        with_isolated_device_vault(
            "ph1d-public-model-json",
            &[("openai_api_key", "test_openai_key")],
            &[
                ("SELENE_PH1D_LIVE_ADAPTER_ENABLED", "true"),
                ("SELENE_PH1D_LIVE_PROVIDER_ID", "openai"),
                ("OPENAI_RESPONSES_URL", endpoint.as_str()),
                ("SELENE_CURL_CONNECT_TIMEOUT", "1"),
                ("SELENE_CURL_MAX_TIME", "5"),
            ],
            || {
                let runtime = AdapterRuntime::default();
                let _ = runtime
                    .ingress
                    .observe_runtime_governance_node_policy_version(
                        "node_public_answer",
                        Some("2026.04.01.v1"),
                    );
                let mut answers = Vec::new();
                for (idx, (prompt, _)) in cases.iter().enumerate() {
                    let mut req = base_request();
                    req.correlation_id = 202_000 + idx as u64;
                    req.turn_id = 203_000 + idx as u64;
                    req.app_platform = "DESKTOP".to_string();
                    req.audio_capture_ref = None;
                    req.thread_key = Some("ph1d_public_joke_diversity".to_string());
                    req.user_text_final = Some((*prompt).to_string());

                    let out = runtime
                        .run_voice_turn(req)
                        .expect("public prompt should complete through PH1.D");
                    assert_eq!(out.status, "ok");
                    assert_eq!(out.outcome, "FINAL");
                    answers.push(out.response_text);
                }
                answers
            },
        )
    }

