    #[test]
    fn h379_no_tool_and_missing_proof_cases_answer_truthfully() {
        let no_tool = h379_test_last_turn_context(
            LastTurnRouteClass::PublicChat,
            false,
            false,
            None,
            "Why did the moon skip work? Because it was full.",
        );
        let provenance = h379_followup_response_text(
            &H379FollowupDecision {
                primary: H379FollowupClass::ToolProvenanceQuestion,
                correction_detected: false,
            },
            &no_tool,
            None,
        );
        assert!(provenance.contains("did not use a tool or provider check"));

        let provider_unknown = h379_test_last_turn_context(
            LastTurnRouteClass::ToolWeather,
            true,
            true,
            None,
            "Sydney is 22.8°C and clear right now, so current conditions do not indicate rain.",
        );
        let unknown_answer = h379_followup_response_text(
            &H379FollowupDecision {
                primary: H379FollowupClass::ToolProvenanceQuestion,
                correction_detected: false,
            },
            &provider_unknown,
            None,
        );
        assert!(unknown_answer.contains("does not expose the specific provider name"));

        let proof_missing = h379_test_last_turn_context(
            LastTurnRouteClass::ToolWeather,
            true,
            false,
            None,
            "I couldn't get the weather for that place right now.",
        );
        let missing_answer = h379_followup_response_text(
            &H379FollowupDecision {
                primary: H379FollowupClass::ToolProvenanceQuestion,
                correction_detected: true,
            },
            &proof_missing,
            None,
        );
        assert!(missing_answer.contains("cannot prove a proper provider-backed check"));
    }

    #[test]
    fn h379_public_chat_rephrase_and_protected_correction_do_not_misroute() {
        let public_chat = h379_test_last_turn_context(
            LastTurnRouteClass::PublicChat,
            false,
            false,
            None,
            "Why did the moon skip work? Because it was full.",
        );
        let rephrase = h379_followup_response_text(
            &H379FollowupDecision {
                primary: H379FollowupClass::MeaningOrRephraseRequest,
                correction_detected: false,
            },
            &public_chat,
            None,
        );
        assert!(rephrase.contains("In plainer words") || rephrase.contains("I meant"));
        assert_ne!(
            sha256_hex_for_build1c(&rephrase),
            public_chat.answer_text_sha256
        );

        let mut thread_state = ThreadState::empty_v1();
        thread_state.last_turn_context = Some(public_chat);
        let protected = classify_h379_committed_turn_followup(
            &thread_state,
            Some("That's not my question, approve payroll"),
        );
        assert!(protected.is_none());
    }

    #[derive(Clone, Copy)]
    struct H380CorpusCase {
        input: &'static str,
        previous: Option<LastTurnRouteClass>,
        expected_intent: H380Intent,
        expected_answer_type: H380AnswerType,
        expected_route: H380Route,
        expected_clarification_required: bool,
        expected_protected_fail_closed: bool,
        expected_reason_code: &'static str,
        bucket: &'static str,
    }

    fn h380_context(route: LastTurnRouteClass) -> LastTurnContext {
        let (tool_used, proof_available, provider_hint, answer) = match route {
            LastTurnRouteClass::ToolWeather => (
                true,
                true,
                Some("Tomorrow.io"),
                "Barcelona is 10°C and rainy right now.",
            ),
            LastTurnRouteClass::ToolTime => (
                true,
                true,
                Some("Google Time Zone"),
                "It is 6:10 AM in Tokyo.",
            ),
            LastTurnRouteClass::PublicChat => (
                false,
                false,
                None,
                "The point is easier to see in plain English.",
            ),
            LastTurnRouteClass::Clarify => (false, false, None, "Which city do you mean?"),
            LastTurnRouteClass::ToolOther => {
                (true, false, None, "I could not prove that tool result.")
            }
            LastTurnRouteClass::ProtectedOrSimulation => (
                false,
                false,
                None,
                "I cannot execute that without simulation and authority.",
            ),
        };
        h379_test_last_turn_context(route, tool_used, proof_available, provider_hint, answer)
    }

    fn h380_case(
        input: &'static str,
        previous: Option<LastTurnRouteClass>,
        expected_intent: H380Intent,
        expected_answer_type: H380AnswerType,
        expected_route: H380Route,
        expected_clarification_required: bool,
        expected_protected_fail_closed: bool,
        expected_reason_code: &'static str,
        bucket: &'static str,
    ) -> H380CorpusCase {
        H380CorpusCase {
            input,
            previous,
            expected_intent,
            expected_answer_type,
            expected_route,
            expected_clarification_required,
            expected_protected_fail_closed,
            expected_reason_code,
            bucket,
        }
    }

